{"Configuration":"/** @param {Context} context */
const SetValue = async (context) => {

    if (!!context?.Form?.InvoicePage?.IssueDateFinal?.Value) {
        return "N/A";
    }

    const grid = context?.Form?.InvoicePage?.InvoiceDetails || [];

    if (grid.length == 0) {
        return "MAROMA";
    }

    const mostRecentAction = grid[0];
    const recentApprover = mostRecentAction?.StatusBy?.Text || "";
    const recentStatus = mostRecentAction?.StatusFinal?.Value || "";
    const stayStatuses = ["Received", "In Review", "Submitted to IOUs"];

    const coordinatorLastNames = ["Cervantes", "Jancik", "Enotiades", "Chavez", "Quintanilla", "Mendez", "Avila", "Rimando"];
    const isCoordinator = coordinatorLastNames.some(name => recentApprover.includes(name));

    const pmLastNames = ["Accardo", "Velores", "Landeros"];
    const isPM = pmLastNames.some(name => recentApprover.includes(name));

    // Pending Corrections - always goes to contractor
    if (recentStatus == "Pending Corrections") {
        return context?.Form?.InvoicePage?.InstallationContractor?.Text || "MAROMA";
    }

    // Corrections Submitted - return to previous actor
    if (recentStatus == "Corrections Submitted") {
        return grid[1]?.StatusBy?.Text || "MAROMA";
    }

    // Rejected - drop down one tier
    if (recentStatus == "Rejected") {
        if (recentApprover == "Roberto Del Real") return "Program Manager";
        if (isPM) return "MAROMA";
        if (isCoordinator) return context?.Form?.InvoicePage?.Contractor?.Text || "MAROMA";
        return "MAROMA";
    }

    // Roberto Del Real routing
    if (recentApprover == "Roberto Del Real") {
        if (stayStatuses.includes(recentStatus)) return "Roberto Del Real";
        if (recentStatus == "Approved") return "Julie Blanco";
    }

    // PM group routing
    if (isPM) {
        if (stayStatuses.includes(recentStatus)) return recentApprover;
        if (recentStatus == "Approved") return "Roberto Del Real";
    }

    // Coordinator group routing
    if (isCoordinator) {
        if (stayStatuses.includes(recentStatus)) return recentApprover;
        if (recentStatus == "Approved") return "Program Manager";
    }

    // Contractor set a stay status - return to last internal reviewer
    if (stayStatuses.includes(recentStatus)) {
        return grid[0]?.UserFilter?.Text || "MAROMA";
    }
};","ClearValueOnTrue":false,"ClearValueOnFalse":false,"Fields":[{"ModelKey":"StatusBy","FieldName":"StatusBy","IsSystemModelKey":false},{"ModelKey":"StatusFinal","FieldName":"StatusFinal","IsSystemModelKey":false},{"ModelKey":"UserFilter","FieldName":"UserFilter","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.InstallationContractor","FieldName":"InstallationContractor","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.IssueDateFinal","FieldName":"IssueDateFinal","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.Contractor","FieldName":"Contractor","IsSystemModelKey":false},{"ModelKey":"Form.InvoicePage.InvoiceDetails","FieldName":"InvoiceDetails","IsSystemModelKey":false}]}

